function updatePlannerLayout(){
  const calendarMode=currentTab==='calendar';
  const plannerVisible=!els.plannerView.classList.contains('hidden');
  // The movable/dockable navigation is now shared by every planner tab.
  els.plannerView.classList.toggle('calendar-mode',calendarMode);
  els.plannerView.classList.toggle('floating-nav-mode',plannerVisible);
  document.body.classList.toggle('planner-workspace',plannerVisible);
  document.body.classList.toggle('calendar-workspace',calendarMode&&plannerVisible);
  if(plannerVisible) restorePlannerNavState();
}
document.querySelectorAll('.tab').forEach(b=>b.onclick=()=>{currentTab=b.dataset.tab;document.querySelectorAll('.tab').forEach(x=>x.classList.toggle('active',x===b));document.querySelectorAll('.tab-panel').forEach(x=>x.classList.toggle('active',x.id===`${currentTab}Tab`));updatePlannerLayout();render()});

let plannerNavState={left:14,top:118,collapsed:false,dock:null};
function readPlannerNavState(){
  try{plannerNavState={...plannerNavState,...JSON.parse(localStorage.getItem('campusCaresFloatingNavV3')||'{}')}}catch{}
}
function savePlannerNavState(){localStorage.setItem('campusCaresFloatingNavV3',JSON.stringify(plannerNavState))}
function clearDockBody(){document.body.classList.remove('nav-docked-left','nav-docked-right','nav-docked-top')}
function applyDock(dock){
  const nav=els.plannerTabs;if(!nav)return;
  nav.classList.remove('dock-left','dock-right','dock-top','collapsed');clearDockBody();
  nav.style.left='';nav.style.top='';nav.style.right='';nav.style.bottom='';
  plannerNavState.dock=dock||null;plannerNavState.collapsed=false;
  if(dock){nav.classList.add(`dock-${dock}`);document.body.classList.add(`nav-docked-${dock}`);els.navUndockBtn?.classList.remove('hidden')}
  else els.navUndockBtn?.classList.add('hidden');
  els.navCollapseBtn.textContent='−';savePlannerNavState();
}
function restorePlannerNavState(){
  const nav=els.plannerTabs;if(!nav||els.plannerView.classList.contains('hidden'))return;
  readPlannerNavState();clearDockBody();nav.classList.remove('dock-left','dock-right','dock-top','collapsed');
  if(plannerNavState.dock){applyDock(plannerNavState.dock);return}
  nav.style.left=`${plannerNavState.left||14}px`;nav.style.top=`${plannerNavState.top||118}px`;nav.style.right='auto';nav.style.bottom='auto';
  nav.classList.toggle('collapsed',!!plannerNavState.collapsed);els.navCollapseBtn.textContent=plannerNavState.collapsed?'+':'−';els.navUndockBtn?.classList.add('hidden');
}
function setupFloatingNavigation(){
  if(!els.plannerTabs||!els.navDragHandle||!els.navCollapseBtn)return;
  readPlannerNavState();
  const dockPreview=document.createElement('div');
  dockPreview.className='dock-preview';
  dockPreview.setAttribute('aria-hidden','true');
  document.body.appendChild(dockPreview);
  let dragging=false,dx=0,dy=0,moved=false,startX=0,startY=0,pendingDock=null;
  const previewDock=dock=>{
    pendingDock=dock||null;
    dockPreview.className=`dock-preview${dock?` show preview-${dock}`:''}`;
    dockPreview.innerHTML=dock?`<div class="dock-preview-label">Dock ${dock}</div>`:'';
  };
  const begin=e=>{
    if(els.plannerView.classList.contains('hidden')||plannerNavState.dock)return;
    const target=e.target;
    const allowed=target===els.navDragHandle||els.plannerTabs.classList.contains('collapsed');
    if(!allowed)return;
    const p=e.touches?.[0]||e,r=els.plannerTabs.getBoundingClientRect();dragging=true;moved=false;startX=p.clientX;startY=p.clientY;dx=p.clientX-r.left;dy=p.clientY-r.top;document.body.classList.add('dragging-nav');e.preventDefault();
  };
  const move=e=>{
    if(!dragging)return;const p=e.touches?.[0]||e;if(Math.hypot(p.clientX-startX,p.clientY-startY)>4)moved=true;
    const maxX=Math.max(8,window.innerWidth-els.plannerTabs.offsetWidth-8),maxY=Math.max(8,window.innerHeight-els.plannerTabs.offsetHeight-8);
    const left=Math.max(8,Math.min(maxX,p.clientX-dx)),top=Math.max(8,Math.min(maxY,p.clientY-dy));
    els.plannerTabs.style.left=`${left}px`;els.plannerTabs.style.top=`${top}px`;els.plannerTabs.style.right='auto';
    plannerNavState.left=left;plannerNavState.top=top;
    const edge=86;
    if(p.clientY<=edge)previewDock('top');
    else if(p.clientX<=edge)previewDock('left');
    else if(p.clientX>=window.innerWidth-edge)previewDock('right');
    else previewDock(null);
    e.preventDefault?.();
  };
  const stop=e=>{
    if(!dragging)return;dragging=false;document.body.classList.remove('dragging-nav');
    const dock=pendingDock;previewDock(null);
    if(moved){if(dock)applyDock(dock);else savePlannerNavState()}
  };
  els.navDragHandle.addEventListener('mousedown',begin);els.navDragHandle.addEventListener('touchstart',begin,{passive:false});
  // When collapsed, the entire small control can be grabbed and moved.
  els.plannerTabs.addEventListener('mousedown',e=>{if(els.plannerTabs.classList.contains('collapsed'))begin(e)});
  els.plannerTabs.addEventListener('touchstart',e=>{if(els.plannerTabs.classList.contains('collapsed'))begin(e)},{passive:false});
  window.addEventListener('mousemove',move);window.addEventListener('touchmove',move,{passive:false});window.addEventListener('mouseup',stop);window.addEventListener('touchend',stop);
  els.navCollapseBtn.onclick=e=>{e.stopPropagation();if(moved){moved=false;return}if(plannerNavState.dock)return;els.plannerTabs.classList.toggle('collapsed');plannerNavState.collapsed=els.plannerTabs.classList.contains('collapsed');els.navCollapseBtn.textContent=plannerNavState.collapsed?'+':'−';savePlannerNavState()};
  els.navUndockBtn.onclick=e=>{e.stopPropagation();applyDock(null);plannerNavState.left=14;plannerNavState.top=118;restorePlannerNavState();savePlannerNavState()};
}
setupFloatingNavigation();
