function renderDashboard(){const root=$('dashboardTab'),a=selectors.assignments(),done=a.filter(x=>x.done).length;root.innerHTML=`<div class="section-card"><div class="eyebrow">${esc(APP_VERSION)}</div><h2>Dashboard</h2><div class="stat-grid"><div class="stat"><div class="num">${selectors.locations().length}</div><div class="label">Locations</div></div><div class="stat"><div class="num">${selectors.tasks().length}</div><div class="label">Tasks</div></div><div class="stat"><div class="num">${a.length}</div><div class="label">Scheduled</div></div><div class="stat"><div class="num">${done}</div><div class="label">Done</div></div></div></div><div class="section-card"><h3>Week 1 progress</h3>${selectors.locations().map(l=>`<div class="progress-row"><div><b>${esc(l.name)}</b>${progress(l)}</div></div>`).join('')||'<div class="empty-note">Add a location first.</div>'}</div>`}
function locationSummary(selected){const locs=selectors.locations(),ids=new Set(selected||[]);if(!locs.length)return 'No locations';if(ids.size===locs.length&&locs.every(l=>ids.has(l.id)))return 'All locations';if(ids.size===1)return locs.find(l=>ids.has(l.id))?.name||'1 location';return ids.size?'Some locations':'Choose locations'}
