function subtaskRow(sub={}){const id=sub.id||uid('sub'),mode=sub.locationMode||'inherit',selected=sub.locationIds||[],locationMinutes=sub.locationMinutes||{};const timeRows=selectors.locations().map(l=>`<label data-location-time-row="${l.id}"><span>${esc(l.name)}</span><input data-sub-location-minutes="${l.id}" type="number" min="0" step="1" value="${locationMinutes[l.id]??''}" placeholder="Default"></label>`).join('');return `<div class="subtask-editor" data-subtask-row="${id}"><span class="drag-handle subtask-drag-handle" draggable="true" data-subtask-drag title="Drag to reorder">⋮⋮</span><input data-sub-name value="${esc(sub.name||'')}" placeholder="Subtask name"><select data-sub-cadence><option value="weekly" ${sub.cadence!=='monthly'?'selected':''}>Weekly</option><option value="monthly" ${sub.cadence==='monthly'?'selected':''}>Once per 4 weeks</option></select><label class="subtask-frequency" title="Times this subtask may be scheduled each week"><input data-sub-weekly type="number" min="1" max="14" step="1" value="${sub.weeklyTarget??1}" ${sub.cadence==='monthly'?'disabled':''}><span>x/week</span></label><label class="subtask-time"><input data-sub-minutes type="number" min="0" step="1" value="${sub.minutes??''}" placeholder="Task default"><span>min</span></label><select data-sub-location-mode><option value="inherit" ${mode==='inherit'?'selected':''}>Use task locations</option><option value="all" ${mode==='all'?'selected':''}>All locations</option><option value="locations" ${mode==='locations'?'selected':''}>Choose locations</option></select>${locationMenu(`sub_${id}`,selected,'sub-location-menu')}<details class="subtask-location-times"><summary>Location times</summary><div>${timeRows||'<span class="task-sub">Add locations first.</span>'}</div></details><button type="button" class="icon-btn" data-remove-subtask="${id}" title="Remove">×</button></div>`}
