function bindTaskForm(f=document.getElementById('taskForm')){if(!f)return;const q=id=>f.querySelector(`#${id}`);bindLocationMenus(f);const rows=q('subtaskRows');const addRow=sub=>{rows.insertAdjacentHTML('beforeend',subtaskRow(sub));bindTaskSubRows(f)};q('addOneSubtask').onclick=()=>addRow({cadence:'weekly',locationMode:'inherit'});q('addBulkSubtasks').onclick=()=>{const names=q('bulkSubtaskNames').value.split('\n').map(x=>x.trim()).filter(Boolean),cadence=q('bulkSubtaskCadence').value;names.forEach(name=>addRow({name,cadence,locationMode:'inherit'}));q('bulkSubtaskNames').value=''};bindTaskSubRows(f);f.onsubmit=async e=>{e.preventDefault();const allIds=selectors.locations().map(l=>l.id),selected=[...f.querySelectorAll('[data-location-check="taskMain"]:checked')].map(x=>x.value);if(allIds.length&&!selected.length){toast('Choose at least one location.','error');return}const subtasks=[...f.querySelectorAll('[data-subtask-row]')].map((row,i)=>{const id=row.dataset.subtaskRow,name=row.querySelector('[data-sub-name]').value.trim(),cadence=row.querySelector('[data-sub-cadence]').value,weeklyTarget=cadence==='monthly'?1:clamp(row.querySelector('[data-sub-weekly]').value,1,14),locationMode=row.querySelector('[data-sub-location-mode]').value,locationIds=[...row.querySelectorAll(`[data-location-check="sub_${id}"]:checked`)].map(x=>x.value),rawMinutes=row.querySelector('[data-sub-minutes]').value,minutes=rawMinutes===''?null:Math.max(0,+rawMinutes||0),locationMinutes={};row.querySelectorAll('[data-sub-location-minutes]').forEach(input=>{if(input.value!=='')locationMinutes[input.dataset.subLocationMinutes]=Math.max(0,+input.value||0)});return name?{id,name,cadence,weeklyTarget,locationMode,locationIds,minutes,locationMinutes,sortOrder:i,archived:false}:null}).filter(Boolean);if(subtasks.some(x=>x.locationMode==='locations'&&!x.locationIds.length)){toast('Choose at least one location for every custom-location subtask.','error');return}const input={name:q('taskName').value,minutes:+q('taskMinutes').value,weeklyTarget:clamp(q('taskWeekly').value,1,14),description:q('taskDescription').value,appliesTo:selected.length===allIds.length?'all':'locations',locationIds:selected,subtasks};const id=q('taskEditId').value;id?await actions.updateTask(id,input):await actions.createTask(input);if(f.closest('.modal-root'))closeModal();renderTasks()}}
function bindTaskSubRows(scope){bindLocationMenus(scope);scope.querySelectorAll('[data-sub-location-mode]').forEach(x=>{const row=x.closest('[data-subtask-row]'),menu=row.querySelector('.sub-location-menu');const update=()=>{menu.classList.toggle('hidden',x.value!=='locations');refreshSubtaskLocationTimes(row,scope)};x.onchange=update;update()});scope.querySelectorAll('[data-sub-cadence]').forEach(x=>{const row=x.closest('[data-subtask-row]'),weekly=row.querySelector('[data-sub-weekly]');const update=()=>{weekly.disabled=x.value==='monthly';if(x.value==='monthly')weekly.value=1};x.onchange=update;update()});scope.querySelectorAll('[data-remove-subtask]').forEach(b=>b.onclick=()=>b.closest('[data-subtask-row]').remove());let dragged=null;scope.querySelectorAll('[data-subtask-drag]').forEach(h=>{h.ondragstart=e=>{dragged=h.closest('[data-subtask-row]');dragged.classList.add('dragging-item');e.dataTransfer.effectAllowed='move'};h.ondragend=()=>{dragged?.classList.remove('dragging-item');dragged=null;scope.querySelectorAll('.drop-before,.drop-after').forEach(x=>x.classList.remove('drop-before','drop-after'))}});scope.querySelectorAll('[data-subtask-row]').forEach(row=>{row.ondragover=e=>{if(!dragged||row===dragged)return;e.preventDefault();scope.querySelectorAll('[data-subtask-row]').forEach(x=>x.classList.remove('drop-before','drop-after'));row.classList.add(e.clientY<row.getBoundingClientRect().top+row.offsetHeight/2?'drop-before':'drop-after')};row.ondrop=e=>{if(!dragged||row===dragged)return;e.preventDefault();const after=e.clientY>=row.getBoundingClientRect().top+row.offsetHeight/2;row.parentNode.insertBefore(dragged,after?row.nextSibling:row);scope.querySelectorAll('.drop-before,.drop-after').forEach(x=>x.classList.remove('drop-before','drop-after'))}})}
function bindTaskCards(){document.querySelectorAll('[data-task-handle]').forEach(h=>h.onclick=e=>e.stopPropagation());bindTaskCardDrag();document.querySelectorAll('[data-expand]').forEach(b=>b.onclick=()=>{store.expandedTaskKey=store.expandedTaskKey===b.dataset.expand?null:b.dataset.expand;renderTasks()});document.querySelectorAll('[data-del]').forEach(b=>b.onclick=async()=>{if(confirm('Delete this task and its calendar items?'))await actions.deleteTask(b.dataset.del)});document.querySelectorAll('[data-edit]').forEach(b=>b.onclick=()=>{const t=selectors.taskById(b.dataset.edit);const root=modal('Edit task',taskForm(t));bindTaskForm(root.querySelector('#taskForm'))})}

function bindTaskCardDrag(){let dragged=null;document.querySelectorAll('[data-task-drag]').forEach(card=>{card.ondragstart=e=>{if(e.target.closest('button,input,select,textarea')&&!e.target.closest('[data-task-handle]')){e.preventDefault();return}dragged=card;card.classList.add('dragging-item');e.dataTransfer.effectAllowed='move';e.dataTransfer.setData('text/plain',card.dataset.taskDrag)};card.ondragend=()=>{card.classList.remove('dragging-item');dragged=null;document.querySelectorAll('.drop-before,.drop-after').forEach(x=>x.classList.remove('drop-before','drop-after'))};card.ondragover=e=>{if(!dragged||card===dragged||card.dataset.taskLocation!==dragged.dataset.taskLocation)return;e.preventDefault();document.querySelectorAll('[data-task-drag]').forEach(x=>x.classList.remove('drop-before','drop-after'));card.classList.add(e.clientY<card.getBoundingClientRect().top+card.offsetHeight/2?'drop-before':'drop-after')};card.ondrop=async e=>{if(!dragged||card===dragged||card.dataset.taskLocation!==dragged.dataset.taskLocation)return;e.preventDefault();const after=e.clientY>=card.getBoundingClientRect().top+card.offsetHeight/2,moved=dragged.dataset.taskDrag,target=card.dataset.taskDrag;await actions.moveTask(moved,target,after);renderTasks()}})}
function renderCalendar(){const root=$('calendarTab'),m=store.data.meta.startMondayISO||isoDate(mondayOf(new Date()));root.innerHTML=`<div class="section-card"><h2>4-week calendar</h2><div class="calendar-controls"><div class="field"><label>Week 1 Monday<input id="startMonday" type="date" value="${m}"></label></div><button id="saveMonday" class="secondary-btn">Save date</button>${[0,1,2,3].map(w=>`<label class="check-chip"><input type="checkbox" data-week-vis="${w}" ${store.data.meta.weekVisibility[w]?'checked':''}>Week ${w+1}</label>`).join('')}</div></div>${[0,1,2,3].filter(w=>store.data.meta.weekVisibility[w]).map(weekHtml).join('')}`;$('saveMonday').onclick=()=>actions.setStartMonday($('startMonday').value);document.querySelectorAll('[data-week-vis]').forEach(x=>x.onchange=()=>actions.setWeekVisible(+x.dataset.weekVis,x.checked));bindCalendar()}
function weekHtml(w){const start=addDays(new Date((store.data.meta.startMondayISO||isoDate(mondayOf(new Date())))+'T00:00:00'),w*7);return `<div class="section-card"><div class="section-head"><h3>Week ${w+1} <span class="task-sub">${prettyDate(isoDate(start))}</span></h3><div class="button-row">${[0,1,2,3].filter(x=>x!==w).map(x=>`<button class="mini-btn" data-copy="${w}_${x}">Copy to W${x+1}</button>`).join('')}</div></div><div class="calendar-grid">${DAY_NAMES.map((n,d)=>dayHtml(w,d,n,isoDate(addDays(start,d)))).join('')}</div></div>`}
function currentDayLocation(w,d){
  const setting=selectors.daySetting(w,d), items=selectors.assignmentsFor(w,d);
  let locationId=setting.locationId||'';
  for(const item of items){if(item.type==='travel'&&item.locationId)locationId=item.locationId}
  return locationId;
}
function timeToMinutes(value){if(!value||!/^\d{2}:\d{2}$/.test(value))return null;const [h,m]=value.split(':').map(Number);return h*60+m}
function displayTime(total){if(total===null)return '';total=((total%1440)+1440)%1440;const h24=Math.floor(total/60),m=total%60,ampm=h24>=12?'PM':'AM',h=h24%12||12;return `${h}:${String(m).padStart(2,'0')} ${ampm}`}
function dayTimeline(items,startTime){let cursor=timeToMinutes(startTime);return items.map(item=>{const start=cursor;if(cursor!==null){if(item.type==='travel')cursor+=+item.travelMinutes||0;else if(item.type==='break')cursor+=+item.breakMinutes||0;else cursor+=selectors.assignmentMinutes(item)}return{item,start}})}
function dayHtml(w,d,n,date){
  const s=selectors.daySetting(w,d),as=selectors.assignmentsFor(w,d),currentLoc=currentDayLocation(w,d),current=selectors.locationById(currentLoc);
  const taskTotal=as.filter(x=>x.type==='task').reduce((sum,x)=>sum+selectors.assignmentMinutes(x),0);
  const timeline=dayTimeline(as,s.startTime||'');
  const report=dayCopyReports.get(`${w}_${d}`);return `<div class="day-card"><div class="day-title"><span>${n}</span><span class="day-title-actions"><button type="button" class="day-copy-btn" data-copy-day="${w}_${d}" title="Copy this day">Copy</button><span class="task-sub">${prettyDate(date)}</span></span></div>${report?copyReportHtml(report,`${w}_${d}`):''}<div class="day-total">Task total: ${formatDuration(taskTotal)}</div><div class="day-setup"><select data-day-loc="${w}_${d}"><option value="">Start location…</option>${selectors.locations().map(l=>`<option value="${l.id}" ${s.locationId===l.id?'selected':''}>${esc(l.name)}</option>`).join('')}</select><input data-day-time="${w}_${d}" type="time" value="${esc(s.startTime||'')}" title="Start time"></div><div class="day-items">${timeline.map((x,i)=>assignmentHtml(x.item,x.start,w,d,segmentForIndex(as,i))).join('')||'<div class="empty-note compact">No items.</div>'}</div><div class="current-location ${currentLoc?'':'muted'}">${currentLoc?`Current: ${esc(current?.name||'Location')}`:'Choose a start location'}</div><select data-picker="${w}_${d}" aria-label="Add task"></select><div class="travel-row"><select data-travel-loc="${w}_${d}" aria-label="Travel destination"><option value="">Travel to…</option>${selectors.locations().filter(l=>l.id!==currentLoc).map(l=>`<option value="${l.id}">${esc(l.name)}</option>`).join('')}</select><input data-travel-min="${w}_${d}" type="number" min="0" placeholder="min" aria-label="Travel minutes"><button class="mini-btn" data-travel="${w}_${d}">Go</button></div><div class="break-row"><input data-break-min="${w}_${d}" type="number" min="1" value="30" aria-label="Lunch break minutes"><button class="mini-btn" data-break="${w}_${d}">Add lunch</button></div></div>`
}

function segmentForIndex(items,index){let segment=0;for(let i=0;i<index;i++)if(items[i].type==='travel')segment++;return segment}
function formatDuration(minutes){const h=Math.floor(minutes/60),m=minutes%60;if(!h)return `${m} min`;if(!m)return `${h} hr`;return `${h} hr ${m} min`}
function assignmentHtml(a,start,w,d,segment){const time=`<div class="assignment-time">${start===null?'':displayTime(start)}</div>`;if(a.type==='travel'){const l=selectors.locationById(a.locationId);return `<div class="assignment-row travel-boundary" data-calendar-item="${a.id}" data-calendar-day="${w}_${d}" data-calendar-segment="${segment}">${time}<div class="assignment travel"><div class="assignment-main"><div class="assignment-name">Travel to ${esc(l?.name||'location')}</div><div class="assignment-meta">${a.travelMinutes||0} minutes</div></div><button class="icon-btn" data-rm="${a.id}">×</button></div></div>`}if(a.type==='break'){return `<div class="assignment-row calendar-draggable" draggable="true" data-calendar-item="${a.id}" data-calendar-day="${w}_${d}" data-calendar-segment="${segment}">${time}<div class="assignment break"><span class="drag-handle calendar-drag-handle" title="Drag to reorder">⋮⋮</span><div class="assignment-main"><div class="assignment-name">Lunch break</div><div class="assignment-meta">${a.breakMinutes||0} minutes</div></div><button class="icon-btn" data-rm="${a.id}">×</button></div></div>`}const t=selectors.taskById(a.taskId),l=selectors.locationById(a.locationId),color=l?.color||'#94a3b8',subs=(a.subtaskIds||[]).map(id=>t?.subtasks?.find(x=>x.id===id)).filter(Boolean),eligibleSubs=t?selectors.eligibleSubtasks(t.id,a.locationId,a.weekIndex,a.id):[],canChooseSubs=subs.length>0||eligibleSubs.length>0;return `<div class="assignment-row calendar-draggable" draggable="true" data-calendar-item="${a.id}" data-calendar-day="${w}_${d}" data-calendar-segment="${segment}">${time}<div class="assignment task-assignment" style="--location-color:${esc(color)}"><span class="drag-handle calendar-drag-handle" title="Drag to reorder">⋮⋮</span><input type="checkbox" data-done="${a.id}" ${a.done?'checked':''}><button type="button" class="assignment-main assignment-edit-target" ${canChooseSubs?`data-edit-assignment-subs="${a.id}" title="Choose items"`:''}><div class="assignment-name">${esc(t?.name||'Missing task')}</div>${subs.length?`<div class="calendar-subtask-status assigned">${subs.length} item${subs.length===1?'':'s'} assigned</div><div class="calendar-subtask-names">${subs.map(x=>`${esc(x.name)} (${selectors.subtaskMinutes(t,x,a.locationId)}m)`).join(' • ')}</div>`:eligibleSubs.length?`<div class="calendar-subtask-status unassigned">Select items</div>`:''}</button><button class="icon-btn" data-rm="${a.id}">×</button></div></div>`}
function bindCalendar(){
  bindCalendarDrag();
  document.querySelectorAll('[data-day-loc]').forEach(x=>{x.onchange=async()=>{const [w,d]=x.dataset.dayLoc.split('_').map(Number);await actions.setDaySetting(w,d,{locationId:x.value});renderCalendar()}});
  document.querySelectorAll('[data-day-time]').forEach(x=>x.onchange=()=>{const [w,d]=x.dataset.dayTime.split('_').map(Number);actions.setDaySetting(w,d,{startTime:x.value})});
  document.querySelectorAll('[data-picker]').forEach(p=>{refreshPicker(p.dataset.picker);p.onchange=async()=>{if(!p.value)return;const k=p.dataset.picker,[w,d]=k.split('_').map(Number),loc=currentDayLocation(w,d),task=selectors.taskById(p.value);p.value='';if(!loc){toast('Choose a start location first.','error');return}p.disabled=true;try{await actions.scheduleTask(task.id,loc,w,d,[]);renderCalendar()}catch(e){p.disabled=false}}});
  document.querySelectorAll('[data-travel]').forEach(b=>b.onclick=async()=>{const k=b.dataset.travel,[w,d]=k.split('_').map(Number),loc=document.querySelector(`[data-travel-loc="${k}"]`).value,min=+document.querySelector(`[data-travel-min="${k}"]`).value;if(loc){await actions.addTravel(loc,w,d,min);renderCalendar()}});
  document.querySelectorAll('[data-break]').forEach(b=>b.onclick=async()=>{const k=b.dataset.break,[w,d]=k.split('_').map(Number),min=+document.querySelector(`[data-break-min="${k}"]`).value||30;await actions.addBreak(w,d,min);renderCalendar()});
  document.querySelectorAll('[data-done]').forEach(x=>x.onchange=()=>actions.toggleAssignment(x.dataset.done,x.checked));
  document.querySelectorAll('[data-rm]').forEach(x=>x.onclick=async()=>{await actions.deleteAssignment(x.dataset.rm);renderCalendar()});
  document.querySelectorAll('[data-edit-assignment-subs]').forEach(x=>x.onclick=()=>openAssignmentSubtaskPicker(x.dataset.editAssignmentSubs));
  document.querySelectorAll('[data-copy]').forEach(x=>x.onclick=async()=>{const [f,t]=x.dataset.copy.split('_').map(Number);if(!confirm(`Replace Week ${t+1} with a copy of Week ${f+1}?`))return;const original=x.innerHTML;x.disabled=true;x.innerHTML='<span class="spinner" aria-hidden="true"></span> Copying…';try{await actions.copyWeek(f,t);renderCalendar();toast(`Week ${t+1} copied.`,'good')}catch(e){x.disabled=false;x.innerHTML=original;toast(e.message||'Could not copy week.','error')}});document.querySelectorAll('[data-copy-day]').forEach(b=>b.onclick=()=>openCopyDayModal(...b.dataset.copyDay.split('_').map(Number)));document.querySelectorAll('[data-dismiss-copy-report]').forEach(b=>b.onclick=()=>{dayCopyReports.delete(b.dataset.dismissCopyReport);b.closest('.copy-report')?.remove()})
}


function copyReportHtml(report,key=''){const skipped=[...(report.skippedTasks||[]),...(report.skippedSubtasks||[]),...(report.skippedOther||[])];if(!skipped.length)return `<div class="copy-report success" title="Everything valid was copied"><span>Copied successfully</span><button type="button" class="copy-report-close" data-dismiss-copy-report="${key}" aria-label="Dismiss copy report" title="Dismiss">×</button></div>`;return `<details class="copy-report warning"><summary>${skipped.length} item${skipped.length===1?'':'s'} not copied</summary><button type="button" class="copy-report-close" data-dismiss-copy-report="${key}" aria-label="Dismiss copy report" title="Dismiss">×</button><div>${skipped.map(x=>`<span>${esc(x)}</span>`).join('')}</div></details>`}
function openCopyDayModal(fromW,fromD){const options=[];for(let w=0;w<4;w++)for(let d=0;d<5;d++)if(w!==fromW||d!==fromD)options.push(`<option value="${w}_${d}">Week ${w+1} — ${DAY_NAMES[d]}</option>`);const root=modal(`Copy ${DAY_NAMES[fromD]}`,`<p class="task-sub">Copies valid tasks, selected subtasks, lunch breaks, and the start time. The destination day will be replaced. Travel entries are not copied.</p><div class="form-grid"><div class="field"><label>Destination day<select id="copyDayTarget">${options.join('')}</select></label></div><div class="field"><label>Destination location<select id="copyDayLocation"><option value="">Choose location…</option>${selectors.locations().map(l=>`<option value="${l.id}">${esc(l.name)}</option>`).join('')}</select></label></div></div>`,`<button id="confirmCopyDay" class="primary-btn">Copy day</button>`);const target=root.querySelector('#copyDayTarget'),location=root.querySelector('#copyDayLocation'),button=root.querySelector('#confirmCopyDay');const syncDefault=()=>{const [w,d]=target.value.split('_').map(Number),existing=selectors.daySetting(w,d).locationId;location.value=existing||''};target.onchange=syncDefault;syncDefault();button.onclick=async()=>{if(!location.value){toast('Choose a destination location.','error');return}const [toW,toD]=target.value.split('_').map(Number);if(!confirm(`Replace Week ${toW+1} ${DAY_NAMES[toD]} with this copied day?`))return;button.disabled=true;const original=button.innerHTML;button.innerHTML='<span class="spinner" aria-hidden="true"></span> Copying…';try{const report=await actions.copyDay(fromW,fromD,toW,toD,location.value);dayCopyReports.set(`${toW}_${toD}`,report);closeModal();renderCalendar();const skipped=(report.skippedTasks?.length||0)+(report.skippedSubtasks?.length||0)+(report.skippedOther?.length||0);toast(skipped?`Day copied with ${skipped} skipped item${skipped===1?'':'s'}.`:'Day copied.','good')}catch(e){button.disabled=false;button.innerHTML=original;toast(e.message||'Could not copy day.','error')}}}

function bindCalendarDrag(){let dragged=null;const clear=()=>document.querySelectorAll('.drop-before,.drop-after,.drop-zone-active').forEach(x=>x.classList.remove('drop-before','drop-after','drop-zone-active'));document.querySelectorAll('.calendar-draggable').forEach(row=>{row.ondragstart=e=>{if(e.target.closest('button,input,select')&&!e.target.closest('.calendar-drag-handle')){e.preventDefault();return}dragged=row;row.classList.add('dragging-item');e.dataTransfer.effectAllowed='move';document.querySelectorAll(`.calendar-draggable[data-calendar-day="${row.dataset.calendarDay}"][data-calendar-segment="${row.dataset.calendarSegment}"]`).forEach(x=>x.classList.add('drop-zone-active'))};row.ondragend=()=>{row.classList.remove('dragging-item');dragged=null;clear()};row.ondragover=e=>{if(!dragged||row===dragged||row.dataset.calendarDay!==dragged.dataset.calendarDay||row.dataset.calendarSegment!==dragged.dataset.calendarSegment)return;e.preventDefault();document.querySelectorAll('.drop-before,.drop-after').forEach(x=>x.classList.remove('drop-before','drop-after'));row.classList.add(e.clientY<row.getBoundingClientRect().top+row.offsetHeight/2?'drop-before':'drop-after')};row.ondrop=async e=>{if(!dragged||row===dragged||row.dataset.calendarDay!==dragged.dataset.calendarDay||row.dataset.calendarSegment!==dragged.dataset.calendarSegment)return;e.preventDefault();const after=e.clientY>=row.getBoundingClientRect().top+row.offsetHeight/2;row.parentNode.insertBefore(dragged,after?row.nextSibling:row);const [w,d]=row.dataset.calendarDay.split('_').map(Number),ids=[...row.closest('.day-items').querySelectorAll('[data-calendar-item]')].map(x=>x.dataset.calendarItem);clear();await actions.reorderAssignments(w,d,ids);renderCalendar()}})}
function refreshPicker(k){const [w,d]=k.split('_').map(Number),loc=currentDayLocation(w,d),p=document.querySelector(`[data-picker="${k}"]`);if(!p)return;const ts=loc?selectors.tasksForLocation(loc).filter(t=>selectors.weeklyAssignedCount(t.id,loc,w)<t.weeklyTarget):[];p.innerHTML=`<option value="">${loc?'Add task…':'Choose start location first'}</option>${ts.map(t=>`<option value="${t.id}">${esc(t.name)} (${selectors.weeklyAssignedCount(t.id,loc,w)}/${t.weeklyTarget})</option>`).join('')}`;p.disabled=!loc||!ts.length}
function openAssignmentSubtaskPicker(assignmentId){
  const a=selectors.assignments().find(x=>x.id===assignmentId),task=a&&selectors.taskById(a.taskId);
  if(!a||!task)return;
  const eligible=selectors.eligibleSubtasks(task.id,a.locationId,a.weekIndex,a.id),selected=new Set(a.subtaskIds||[]);
  if(!eligible.length&&!selected.size){toast('No items are available for this location and period.','error');return}
  const choices=eligible.map(s=>`<label><input type="checkbox" data-choose-subtask value="${s.id}" ${selected.has(s.id)?'checked':''}><span><b>${esc(s.name)}</b><small>${s.cadence==='monthly'?'Once in this 4-week planner':`${s.weeklyTarget||1}x each week`} • ${selectors.subtaskMinutes(task,s,a.locationId)} min</small></span></label>`).join('');
  const root=modal(task.name,`<p class="task-sub">Choose the items for this specific week. The calendar task can remain unassigned while you build and copy your schedule.</p><div class="subtask-choice-toolbar"><button id="selectAllEligible" type="button" class="mini-btn">Select all available</button><button id="clearSelectedItems" type="button" class="mini-btn">Clear</button></div><div class="subtask-choice-list">${choices||'<div class="empty-note">No available items.</div>'}</div>`,`<button id="saveAssignmentSubtasks" class="primary-btn">Save items</button>`);
  root.querySelector('#selectAllEligible').onclick=()=>root.querySelectorAll('[data-choose-subtask]').forEach(x=>x.checked=true);
  root.querySelector('#clearSelectedItems').onclick=()=>root.querySelectorAll('[data-choose-subtask]').forEach(x=>x.checked=false);
  root.querySelector('#saveAssignmentSubtasks').onclick=async()=>{const ids=[...root.querySelectorAll('[data-choose-subtask]:checked')].map(x=>x.value);root.querySelector('#saveAssignmentSubtasks').disabled=true;try{await actions.updateAssignmentSubtasks(a.id,ids);closeModal();renderCalendar()}catch(e){root.querySelector('#saveAssignmentSubtasks').disabled=false}};
}
function renderLocations(){const r=$('locationsTab');r.innerHTML=`<div class="section-card"><h2>Locations</h2><form id="locForm" class="button-row"><input id="locName" placeholder="Location name"><input id="locColor" type="color" value="#2563eb"><button class="primary-btn">Add</button></form></div><div class="section-card"><div class="loc-list">${selectors.locations().map(l=>`<div class="loc-card"><div class="location-title"><input class="location-color-picker" type="color" value="${esc(l.color)}" data-loc-color="${l.id}" title="Choose calendar color"><span>${esc(l.name)}</span></div>${progress(l)}<div class="detail-actions"><button class="mini-btn" data-loc-edit="${l.id}">Rename</button><button class="danger-btn" data-loc-del="${l.id}">Archive</button></div></div>`).join('')}</div></div>`;$('locForm').onsubmit=async e=>{e.preventDefault();await actions.createLocation($('locName').value,$('locColor').value)};document.querySelectorAll('[data-loc-color]').forEach(x=>x.onchange=()=>actions.updateLocation(x.dataset.locColor,{color:x.value}));document.querySelectorAll('[data-loc-edit]').forEach(b=>b.onclick=async()=>{const l=selectors.locationById(b.dataset.locEdit),name=prompt('Location name',l.name);if(name)await actions.updateLocation(l.id,{name})});document.querySelectorAll('[data-loc-del]').forEach(b=>b.onclick=()=>confirm('Archive this location?')&&actions.deleteLocation(b.dataset.locDel))}
function renderUnfinished(){const r=$('unfinishedTab'),today=new Date();today.setHours(0,0,0,0);const start=new Date((store.data.meta.startMondayISO||isoDate(mondayOf(new Date())))+'T00:00:00');const items=selectors.assignments().filter(a=>a.type==='task'&&!a.done&&addDays(start,a.weekIndex*7+a.dayIndex)<today);r.innerHTML=`<div class="section-card"><h2>Unfinished tasks</h2><p class="task-sub">Past scheduled items that are not checked off.</p>${items.map(a=>{const t=selectors.taskById(a.taskId),l=selectors.locationById(a.locationId),date=isoDate(addDays(start,a.weekIndex*7+a.dayIndex));return `<div class="progress-row"><div><b>${esc(t?.name||'Missing task')}</b><div class="task-sub">${esc(l?.name||'')} • ${prettyDate(date)}</div></div><button class="mini-btn" data-finish="${a.id}">Mark done</button></div>`}).join('')||'<div class="empty-note">Nothing unfinished.</div>'}</div>`;document.querySelectorAll('[data-finish]').forEach(b=>b.onclick=()=>actions.toggleAssignment(b.dataset.finish,true))}
function trackedFieldInput(t,f){const base=`data-track-task="${t.id}" data-track-field="${f.id}"`;if(f.type==='checkbox')return `<input ${base} type="checkbox" ${f.value?'checked':''}>`;if(f.type==='textarea')return `<textarea ${base}>${esc(f.value||'')}</textarea>`;return `<input ${base} type="${['date','number'].includes(f.type)?f.type:'text'}" value="${esc(f.value??'')}">`}
function renderTracked(){const r=$('trackedTab');r.innerHTML=`<div class="section-card"><div class="section-head"><div><h2>Tracked Tasks</h2><p>Custom form-style compliance and recurring records.</p></div><button id="newTracked" class="primary-btn">Add tracked task</button></div><div class="tracked-grid">${selectors.trackedTasks().map(t=>`<div class="loc-card"><div class="section-head"><div><h3>${esc(t.title)}</h3><div class="task-sub">${t.locationId==='all'?'All locations':esc(selectors.locationById(t.locationId)?.name||'')}</div></div><button class="danger-btn" data-track-del="${t.id}">Delete</button></div>${t.fields.map(f=>`<div class="field tracked-field"><label>${esc(f.label)}${trackedFieldInput(t,f)}</label></div>`).join('')}</div>`).join('')||'<div class="empty-note">No tracked tasks.</div>'}</div></div><div class="section-card"><h3>Bulk add a field</h3><form id="bulkField" class="form-grid"><div class="field"><label>Location<select id="bulkLoc"><option value="all">All</option>${selectors.locations().map(l=>`<option value="${l.id}">${esc(l.name)}</option>`).join('')}</select></label></div><div class="field"><label>Title contains<input id="bulkSearch"></label></div><div class="field"><label>Field label<input id="bulkLabel" required></label></div><div class="field"><label>Type<select id="bulkType"><option>text</option><option>date</option><option>checkbox</option><option>number</option><option>textarea</option></select></label></div><div class="field full"><button class="secondary-btn">Add to matching tasks</button></div></form></div>`;$('newTracked').onclick=openTrackedBuilder;document.querySelectorAll('[data-track-del]').forEach(b=>b.onclick=()=>confirm('Delete tracked task?')&&actions.deleteTracked(b.dataset.trackDel));document.querySelectorAll('[data-track-field]').forEach(x=>x.onchange=()=>actions.saveTrackedField(x.dataset.trackTask,x.dataset.trackField,x.type==='checkbox'?x.checked:x.value));$('bulkField').onsubmit=async e=>{e.preventDefault();await actions.bulkAddTrackedField({locationId:$('bulkLoc').value,search:$('bulkSearch').value},{label:$('bulkLabel').value,type:$('bulkType').value,highlightEnabled:false,expiryDays:28});renderTracked()}}
function openTrackedBuilder(){modal('Add tracked task',`<form id="trackedForm" class="form-grid"><div class="field wide"><label>Title<input id="trackedTitle" required></label></div><div class="field"><label>Location<select id="trackedLoc"><option value="all">All locations</option>${selectors.locations().map(l=>`<option value="${l.id}">${esc(l.name)}</option>`).join('')}</select></label></div><div class="field full"><label>Fields, one per line <span class="task-sub">Format: Label | type</span><textarea id="trackedFields" rows="8" placeholder="Date Completed | date\nCompleted By | text\nPassed | checkbox"></textarea></label></div><div class="field full"><button class="primary-btn">Create tracked task</button></div></form>`);$('trackedForm').onsubmit=async e=>{e.preventDefault();const fields=$('trackedFields').value.split('\n').map(x=>x.trim()).filter(Boolean).map(line=>{const [label,type='text']=line.split('|').map(x=>x.trim());return{id:uid('field'),label,type,value:type==='checkbox'?false:'',highlightEnabled:false,expiryDays:28}});await actions.createTracked({title:$('trackedTitle').value,locationId:$('trackedLoc').value,fields});closeModal();renderTracked()}}
async function openHistory(){if(!store.loaded)return;const h=await loadHistory();modal('Save history',`<button id="exportBackup" class="secondary-btn">Download JSON backup</button>${h.map((x,i)=>`<div class="history-item"><div><b>${esc(x.reason||'Snapshot')}</b><div class="task-sub">${x.createdAt?.toDate?x.createdAt.toDate().toLocaleString():'Saved snapshot'}</div></div><button class="mini-btn" data-restore="${i}">Restore</button></div>`).join('')||'<div class="empty-note">No history.</div>'}`);$('exportBackup').onclick=()=>downloadJson('campus-cares-backup.json',store.data);document.querySelectorAll('[data-restore]').forEach(b=>b.onclick=async()=>{if(confirm('Restore this snapshot?')){await actions.restoreHistory(h[+b.dataset.restore]);closeModal();render()}})}


const issueExpanded=new Set();
const ISSUE_STATUSES=['Documented','Solution Decided','Materials Required','In-Progress','Completed','Dismiss'];
function issueAssigneeRows(values=['']){return values.map((v,i)=>`<div class="issue-assignee-row"><input data-issue-assignee value="${esc(v)}" placeholder="Name"><button type="button" class="mini-btn issue-remove-person" aria-label="Remove person">−</button>${i===values.length-1&&String(v).trim()?'<button type="button" class="mini-btn issue-add-person" aria-label="Add another person">+</button>':''}</div>`).join('')}
function bindIssueAssignees(root){const box=root.querySelector('[data-issue-assignees]');if(!box)return;const refreshButtons=()=>{const rows=[...box.querySelectorAll('.issue-assignee-row')];rows.forEach((row,i)=>{row.querySelector('.issue-add-person')?.remove();if(i===rows.length-1&&row.querySelector('[data-issue-assignee]')?.value.trim()){const add=document.createElement('button');add.type='button';add.className='mini-btn issue-add-person';add.setAttribute('aria-label','Add another person');add.textContent='+';add.onclick=()=>{box.insertAdjacentHTML('beforeend',issueAssigneeRows(['']));bindRows();box.querySelectorAll('[data-issue-assignee]')[box.querySelectorAll('[data-issue-assignee]').length-1]?.focus()};row.appendChild(add)}})};const bindRows=()=>{box.querySelectorAll('[data-issue-assignee]').forEach(input=>{input.oninput=refreshButtons});box.querySelectorAll('.issue-remove-person').forEach(b=>b.onclick=()=>{const rows=box.querySelectorAll('.issue-assignee-row');if(rows.length===1){const input=b.closest('.issue-assignee-row').querySelector('[data-issue-assignee]');input.value='';input.focus()}else b.closest('.issue-assignee-row').remove();refreshButtons()});refreshButtons()};bindRows()}
function issueCard(x){const open=issueExpanded.has(x.id),loc=x.locationId==='all'?null:selectors.locationById(x.locationId);return `<div class="issue-card ${open?'open':''}" data-issue-card="${x.id}"><button class="issue-card-head" data-issue-expand="${x.id}"><span>${esc(x.name)}</span><span class="issue-status-badge">${esc(x.status)}</span></button>${open?`<div class="issue-card-body"><div class="issue-meta"><span>${x.locationId==='all'?'All locations':esc(loc?.name||'No location')}</span>${x.assignedTo.length?`<span>Assigned: ${x.assignedTo.map(esc).join(', ')}</span>`:''}</div><p>${esc(x.description).replace(/\n/g,'<br>')}</p>${x.photoUrl?`<a href="${esc(x.photoUrl)}" target="_blank" rel="noopener"><img class="issue-photo" src="${esc(x.photoUrl)}" alt="Photo of ${esc(x.name)}"></a>`:''}<div class="issue-actions-row"><label class="field">Status<select data-issue-status="${x.id}">${ISSUE_STATUSES.map(v=>`<option ${v===x.status?'selected':''}>${v}</option>`).join('')}</select></label><button type="button" class="danger-btn issue-delete-btn" data-delete-issue="${x.id}">Delete permanently</button></div><div class="issue-chat"><h4>Discussion</h4><div class="issue-messages" data-issue-messages="${x.id}">${x.messages.map(m=>`<div class="issue-message"><b>${esc(m.author||'Team member')}</b><span>${esc(m.text)}</span><small>${new Date(m.createdAt).toLocaleString()}</small></div>`).join('')||'<div class="empty-note">No messages yet.</div>'}</div><form data-issue-chat="${x.id}" class="issue-chat-form"><input data-issue-author value="${esc(currentAuthor())}" readonly><input data-issue-message placeholder="Add a thought or update" required><button class="mini-btn">Send</button></form></div></div>`:''}</div>`}
function issueFormHtml(){const locs=selectors.locations();return `<form id="issueForm" class="form-grid issue-form-grid modal-issue-form"><div class="field"><label>Location<select id="issueLocation" required><option value="">Choose location</option><option value="all">All locations</option>${locs.map(l=>`<option value="${l.id}">${esc(l.name)}</option>`).join('')}</select></label></div><div class="field wide"><label>Issue name<input id="issueName" required></label></div><div class="field full"><label>Description<textarea id="issueDescription" rows="4" required></textarea></label></div><div class="field full"><label>Photo<input id="issuePhoto" type="file" accept="image/*" capture="environment"></label><div class="task-sub">On a phone, this can open the camera.</div></div><div class="field full issue-assignee-field"><label>Assigned to</label><div data-issue-assignees>${issueAssigneeRows([''])}</div></div><div class="field full"><button id="saveIssueBtn" class="primary-btn">Document issue</button></div></form>`}
function renderIssues(){const r=$('issuesTab'),locs=selectors.locations();r.innerHTML=`<div class="section-card compact-section-head"><div class="section-head"><div><h2>Documented Issues</h2><p>Record campus problems, photos, assignments, status changes, and discussion.</p></div><button id="openDocumentIssue" class="primary-btn">Document Task</button></div></div><div class="section-card"><div class="locations-board">${locs.map(l=>`<div class="location-column"><div class="location-head"><div class="location-title"><span class="color-dot" style="background:${l.color}"></span>${esc(l.name)}</div></div>${selectors.issues().filter(x=>x.locationId===l.id).map(issueCard).join('')||'<div class="empty-note">No documented issues.</div>'}</div>`).join('')}</div></div>`;$('openDocumentIssue').onclick=()=>{const m=modal('Document Task',issueFormHtml());bindIssueAssignees(m);m.querySelector('#issueForm').onsubmit=saveIssue};document.querySelectorAll('[data-issue-expand]').forEach(b=>b.onclick=()=>{issueExpanded.has(b.dataset.issueExpand)?issueExpanded.delete(b.dataset.issueExpand):issueExpanded.add(b.dataset.issueExpand);renderIssues()});document.querySelectorAll('[data-issue-status]').forEach(x=>x.onchange=async()=>{const old=selectors.issueById(x.dataset.issueStatus)?.status||'Documented';if(x.value==='Dismiss'){const reason=prompt('Reason for dismissal:');if(reason===null||!reason.trim()){x.value=old;return}await actions.setIssueStatus(x.dataset.issueStatus,x.value,reason)}else if(x.value==='Completed'){if(!confirm('Mark this issue completed and move it to the hidden completed log?')){x.value=old;return}await actions.setIssueStatus(x.dataset.issueStatus,x.value)}else await actions.setIssueStatus(x.dataset.issueStatus,x.value);renderIssues()});document.querySelectorAll('[data-delete-issue]').forEach(b=>b.onclick=async()=>{if(!confirm('Permanently delete this issue? It will not be saved in a log.'))return;const issue=selectors.issueById(b.dataset.deleteIssue);if(issue?.photoPath)await deleteObject(ref(storage,issue.photoPath)).catch(()=>{});await actions.deleteIssue(b.dataset.deleteIssue);issueExpanded.delete(b.dataset.deleteIssue);renderIssues()});document.querySelectorAll('[data-issue-chat]').forEach(f=>f.onsubmit=async e=>{e.preventDefault();const msg=f.querySelector('[data-issue-message]').value;await actions.addIssueMessage(f.dataset.issueChat,msg,currentAuthor());renderIssues();requestAnimationFrame(()=>{const box=document.querySelector(`[data-issue-messages="${f.dataset.issueChat}"]`);if(box)box.scrollTop=box.scrollHeight})});requestAnimationFrame(()=>document.querySelectorAll('[data-issue-messages]').forEach(box=>box.scrollTop=box.scrollHeight))}
async function saveIssue(e){e.preventDefault();const form=e.currentTarget,btn=form.querySelector('#saveIssueBtn'),file=form.querySelector('#issuePhoto').files?.[0];btn.disabled=true;btn.innerHTML='<span class="spinner"></span> Saving…';try{let photoUrl='',photoPath='';if(file){const safe=file.name.replace(/[^a-zA-Z0-9._-]/g,'_');photoPath=`users/${auth.currentUser.uid}/documentedIssues/${Date.now()}-${safe}`;const rr=ref(storage,photoPath);await uploadBytes(rr,file,{contentType:file.type||'image/jpeg'});photoUrl=await getDownloadURL(rr)}const assignedTo=[...form.querySelectorAll('[data-issue-assignee]')].map(x=>x.value.trim()).filter(Boolean),selectedLocation=form.querySelector('#issueLocation').value,locationIds=selectedLocation==='all'?selectors.locations().map(l=>l.id):[selectedLocation],base={name:form.querySelector('#issueName').value,description:form.querySelector('#issueDescription').value,assignedTo,photoUrl,photoPath,status:'Documented',messages:[]};for(const locationId of locationIds)await actions.createIssue({...base,locationId});closeModal();renderIssues();toast(locationIds.length>1?'Independent issues added to all locations.':'Issue documented.','good')}catch(err){console.error(err);toast(err.message||'Could not save issue.','error');btn.disabled=false;btn.textContent='Document issue'}}
